type stateX struct {
        Rows   []itemY
        ByPath map[string]int
}

type itemY = f5.Row

func phase_a(a *stateX, b itemY) error {
        if a.ByPath == nil {
                a.ByPath = map[string]int{}
        }
        if b.Path == "" {
                return nil
        }
        if b.Op == "write" && b.Seq%5 == 0 {
                b.Data = strings.TrimSuffix(b.Data, "\n")
